class LoginPage:
    url = "/login"   # class variable (shared by all instances)

    def __init__(self, driver):
        self.driver = driver   # instance variable

    def login(self, username, password):
        self.driver.find("#user").send_keys(username)
        self.driver.find("#pass").send_keys(password)
        self.driver.find("#btn").click()

    @classmethod
    def get_url(cls):         # access class variable
        return cls.url

    @staticmethod
    def validate(u):          # no self/cls needed
        return bool(u)

# Instantiate
