page.login("admin", "pass123")

class BasePage:
    def __init__(self, driver):
        self.driver = driver

    def wait_for(self, locator):
        return self.driver.find(locator)   # shared by all pages

    def screenshot(self, name):
        self.driver.save_screenshot(name)

class LoginPage(BasePage):    # inherits BasePage
    def login(self, u, p):
        self.wait_for("#user").send_keys(u)   # parent method!
        self.wait_for("#pass").send_keys(p)
        self.wait_for("#btn").click()

class AdminPage(LoginPage):
    def __init__(self, driver, token):
        super().__init__(driver)    # call parent __init__
        self.token = token

import functools, time

def log_test(func):
    @functools.wraps(func)   # preserves func name
    def wrapper(*args, **kwargs):
        print(f"START: {func.__name__}")
        result = func(*args, **kwargs)
        print(f"END:   {func.__name__}")
        return result
    return wrapper

