# Decorator with arguments — retry pattern
def retry(times=3, delay=1):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*a, **k):
            for i in range(times):
                try: return func(*a, **k)
                except Exception as e:
                    if i == times-1: raise
                    time.sleep(delay)
        return wrapper
    return decorator

@retry(times=3, delay=2)
def flaky_api_call(): ...

