import pytest, os
from playwright.sync_api import sync_playwright

@pytest.fixture(scope="session")
def browser():
    with sync_playwright() as p:
        b = p.chromium.launch(headless=True)
        yield b
        b.close()

@pytest.fixture
def base_url():
    return os.getenv("BASE_URL", "https://staging.example.com")

@pytest.fixture
def test_user():
    return {"username": "admin", "password": "pass123"}

# ── In any test file — NO import needed ──
def test_login(browser, base_url, test_user):
    page = browser.new_page()
    page.goto(base_url + "/login")
    page.fill("#user", test_user["username"])
    page.fill("#pass", test_user["password"])
